/*
  Design system and layout styles for precision CNC manufacturing site
  Matches corporate/industrial header + nav style from reference design.
*/

:root {
  /* Brand colors */
  --color-primary-900: #0B315F; /* Dark brand blue - nav background */
  --color-primary-700: #0078C8; /* Bright brand blue - logo accent */

  --color-secondary-800: #1A4B80; /* Medium blue for hover/accents */
  --color-secondary-600: #555555; /* Secondary text */

  --color-accent-500: #F5C84A; /* Highlight/accent */

  --color-neutral-000: #FFFFFF; /* White */
  --color-neutral-050: #F5F5F5; /* Light gray background */
  --color-neutral-800: #333333; /* Primary body text */

  --color-success: #2E8B57;
  --color-error: #C0392B;
  --color-warning: #F39C12;
  --color-info: #2980B9;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --font-size-h1: 2.25rem; /* ~36px */
  --font-size-h2: 1.75rem; /* ~28px */
  --font-size-h3: 1.375rem; /* ~22px */
  --font-size-body: 1rem;    /* 16px */
  --font-size-small: 0.8125rem; /* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-0: 0;
  --space-1: 0.25rem;  /* 4px */
  --space-2: 0.5rem;   /* 8px */
  --space-3: 1rem;     /* 16px */
  --space-4: 1.5rem;   /* 24px */
  --space-5: 2rem;     /* 32px */
  --space-6: 3rem;     /* 48px */
  --space-7: 4rem;     /* 64px */

  /* Layout */
  --layout-max-width: 1140px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-050);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-primary-700);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  font-weight: 600;
  line-height: var(--line-height-tight);
  margin: 0 0 var(--space-3);
  color: var(--color-primary-900);
}

p {
  margin: 0 0 var(--space-3);
}

.site-header {
  background-color: var(--color-neutral-000);
  border-bottom: 1px solid #E0E0E0;
}

.header-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: center; /* Logo centered as in design */
}

.branding {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

.logo-mark {
  width: 96px;
  height: 56px;
  background: linear-gradient(135deg, var(--color-primary-900) 0%, var(--color-primary-700) 50%, #000000 100%);
  position: relative;
  clip-path: polygon(10% 0, 100% 0, 90% 50%, 100% 100%, 10% 100%, 0 50%);
}

.logo-mark::before {
  content: '';
  position: absolute;
  inset: 18%;
  background: repeating-linear-gradient(90deg, #FFFFFF 0, #FFFFFF 6%, #1E5A92 6%, #1E5A92 10%);
  clip-path: polygon(0 0, 100% 0, 70% 50%, 100% 100%, 0 100%, 30% 50%);
  opacity: 0.85;
}

.logo-text {
  display: flex;
  flex-direction: column;
  text-transform: uppercase;
}

.logo-title {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 1.875rem; /* ~30px */
  letter-spacing: 0.12em;
  color: #0078C8;
}

.logo-subtitle {
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.875rem;
  letter-spacing: 0.22em;
  color: #999999;
}

/* Primary navigation bar */

.primary-nav {
  background-color: var(--color-primary-900);
}

.nav-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  align-items: stretch;
  flex-wrap: wrap;
}

.nav-item {
  margin: 0;
}

.nav-item a {
  display: block;
  padding: 0.9rem 1.1rem; /* ~14px x 18px */
  font-family: var(--font-body);
  font-weight: 500;
  font-size: 0.94rem;
  letter-spacing: 0.04em;
  color: var(--color-neutral-000);
  text-decoration: none;
  white-space: nowrap;
}

.nav-item a:hover,
.nav-item a:focus {
  background-color: var(--color-secondary-800);
}

.nav-item a[aria-current='page'] {
  background-color: #11437A;
}

/* Main content wrapper */

.site-main {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-6) var(--space-3) var(--space-7);
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-000);
}

.footer-top {
  border-top: 4px solid var(--color-primary-700);
  padding: var(--space-5) var(--space-3) var(--space-4);
}

.footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
}

.footer-branding {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin-bottom: var(--space-4);
}

.footer-logo-mark {
  width: 72px;
  height: 42px;
  background: linear-gradient(135deg, var(--color-primary-700) 0%, var(--color-primary-900) 100%);
  clip-path: polygon(10% 0, 100% 0, 90% 50%, 100% 100%, 10% 100%, 0 50%);
  opacity: 0.9;
}

.footer-logo-text {
  display: flex;
  flex-direction: column;
}

.footer-logo-title {
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.footer-logo-tagline {
  font-family: var(--font-body);
  font-size: 0.8rem;
  color: rgba(255, 255, 255, 0.75);
  margin-top: 0.15rem;
}

.footer-nav {
  margin-top: var(--space-1);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem 1.75rem;
}

.footer-links li {
  margin: 0;
}

.footer-links a {
  font-size: 0.9rem;
  color: rgba(255, 255, 255, 0.92);
  text-decoration: none;
}

.footer-links a:hover,
.footer-links a:focus {
  text-decoration: underline;
}

.footer-bottom {
  background-color: #082546;
  border-top: 1px solid rgba(255, 255, 255, 0.16);
}

.footer-bottom-inner {
  padding: var(--space-2) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-copy {
  margin: 0;
  font-size: var(--font-size-small);
  color: rgba(255, 255, 255, 0.75);
}

/* Utility classes for potential page layouts (optional, non-specific) */

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.section {
  margin-bottom: var(--space-6);
}

.section:last-child {
  margin-bottom: 0;
}

.btn-primary {
  display: inline-block;
  padding: 0.65rem 1.5rem;
  border-radius: 2px;
  border: none;
  background-color: var(--color-primary-700);
  color: var(--color-neutral-000);
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  text-decoration: none;
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: var(--color-secondary-800);
}

/* Responsive adjustments */

@media (max-width: 900px) {
  .header-inner {
    padding: var(--space-3) var(--space-3);
  }

  .logo-title {
    font-size: 1.5rem;
  }

  .logo-subtitle {
    letter-spacing: 0.18em;
  }

  .nav-item a {
    padding: 0.7rem 0.9rem;
    font-size: 0.9rem;
  }

  .footer-branding {
    flex-direction: column;
    align-items: flex-start;
  }
}

@media (max-width: 640px) {
  .logo-mark {
    width: 72px;
    height: 42px;
  }

  .brandishing,
  .branding {
    flex-direction: row;
  }

  .nav-list {
    justify-content: flex-start;
    overflow-x: auto;
    white-space: nowrap;
  }

  .nav-item a {
    padding-inline: 0.85rem;
  }

  .site-main {
    padding-inline: var(--space-2);
  }

  .footer-links {
    flex-direction: column;
  }
}
